[Authorize]
[HttpGet("Array/GetChilds")]
public async Task<ActionResult<List<ChildsInParent>>> ArrayGetChilds(string ChildOrParent, int? PartID = null, int? AreaID = null, string? Side = null, bool sortAlphabetic = false)
{
    try
    {
        var ChildsInArray = await _UnitsService.ArrayGetChildsAsync(ChildOrParent, PartID, AreaID, Side, sortAlphabetic);

        return Ok(ChildsInArray);
    }
    catch (InvalidOperationException ex)
    {
        return BadRequest(ex.Message); // Devuelve un mensaje de error
    }
